}

pub enum MenuItem {
    Label { text: String },
    Separator,
    Action { id: String, text: String, enabled: bool, checked: bool },
    Submenu { text: String, items: Vec<MenuItem> },
}

pub enum TrayEvent {
    MenuAction(String),
    LeftClick,
    RightClick,
