### Linux Implementation (GTK StatusIcon / AppIndicator)

```rust
// src/tray/linux.rs

use gtk::prelude::*;
use libappindicator::{AppIndicator, AppIndicatorStatus};

pub struct LinuxTray {
    indicator: AppIndicator,
    menu: gtk::Menu,
}

impl SystemTray for LinuxTray {
    fn new() -> Result<Self, TrayError> {
        gtk::init()?;

        let mut indicator = AppIndicator::new("surface-dial", "audio-volume-medium");
        indicator.set_status(AppIndicatorStatus::Active);

        let menu = gtk::Menu::new();
        indicator.set_menu(&mut menu);

        Ok(Self { indicator, menu })
    }

    fn set_icon(&mut self, icon: TrayIcon) {
        let icon_name = match icon {
            TrayIcon::Connected => "audio-volume-high",
            TrayIcon::Disconnected => "audio-volume-muted",
            TrayIcon::LowBattery => "battery-low",
            TrayIcon::Muted => "audio-volume-muted",
        };
        self.indicator.set_icon(icon_name);
    }

    fn set_menu(&mut self, menu: TrayMenu) {
        // Clear and rebuild menu
        self.menu.foreach(|child| self.menu.remove(child));

        for item in menu.items {
            match item {
                MenuItem::Label { text } => {
                    let menu_item = gtk::MenuItem::with_label(&text);
                    menu_item.set_sensitive(false);
                    self.menu.append(&menu_item);
                }
                MenuItem::Separator => {
                    self.menu.append(&gtk::SeparatorMenuItem::new());
                }
                MenuItem::Action { id, text, enabled, checked } => {
                    let menu_item = if checked {
                        let item = gtk::CheckMenuItem::with_label(&text);
                        item.set_active(true);
                        item.upcast::<gtk::MenuItem>()
                    } else {
                        gtk::MenuItem::with_label(&text)
                    };
                    menu_item.set_sensitive(enabled);
                    let id_clone = id.clone();
                    menu_item.connect_activate(move |_| {
                        // Send event back to daemon
                        send_tray_event(TrayEvent::MenuAction(id_clone.clone()));
                    });
                    self.menu.append(&menu_item);
                }
                // ...
            }
        }
        self.menu.show_all();
    }
}
