// src/tray/windows.rs

use windows::Win32::UI::Shell::*;
use windows::Win32::UI::WindowsAndMessaging::*;

pub struct WindowsTray {
    hwnd: HWND,
    nid: NOTIFYICONDATAW,
}

impl SystemTray for WindowsTray {
    fn new() -> Result<Self, TrayError> {
        unsafe {
            // Create hidden window for messages
            let hwnd = CreateWindowExW(
                WINDOW_EX_STYLE::default(),
                w!("STATIC"),
                w!("Surface Dial Tray"),
                WS_OVERLAPPED,
                0, 0, 0, 0,
                None, None, None, None,
            );

            // Create tray icon
            let mut nid = NOTIFYICONDATAW {
                cbSize: std::mem::size_of::<NOTIFYICONDATAW>() as u32,
                hWnd: hwnd,
                uID: 1,
                uFlags: NIF_ICON | NIF_MESSAGE | NIF_TIP,
                uCallbackMessage: WM_USER + 1,
                hIcon: LoadIconW(None, IDI_APPLICATION)?,
                ..Default::default()
            };

            // Set tooltip
            let tip = "Surface Dial";
            let tip_wide: Vec<u16> = tip.encode_utf16().chain(std::iter::once(0)).collect();
            nid.szTip[..tip_wide.len()].copy_from_slice(&tip_wide);

            Shell_NotifyIconW(NIM_ADD, &nid)?;

            Ok(Self { hwnd, nid })
        }
    }

    fn set_icon(&mut self, icon: TrayIcon) {
        unsafe {
            let hicon = match icon {
                TrayIcon::Connected => LoadIconW(None, IDI_APPLICATION),
                TrayIcon::Disconnected => LoadIconW(None, IDI_WARNING),
                // Load custom icons from resources...
                _ => LoadIconW(None, IDI_APPLICATION),
            }.unwrap();

            self.nid.hIcon = hicon;
            Shell_NotifyIconW(NIM_MODIFY, &self.nid);
        }
    }

